rules:
@-webkit-keyframes notyf-fadeinup { 
  0% { opacity: 0; transform: translateY(25%); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes notyf-fadeinup { 
  0% { opacity: 0; transform: translateY(25%); }
  100% { opacity: 1; transform: translateY(0px); }
}

@-webkit-keyframes notyf-fadeinleft { 
  0% { opacity: 0; transform: translateX(25%); }
  100% { opacity: 1; transform: translateX(0px); }
}

@keyframes notyf-fadeinleft { 
  0% { opacity: 0; transform: translateX(25%); }
  100% { opacity: 1; transform: translateX(0px); }
}

@-webkit-keyframes notyf-fadeoutright { 
  0% { opacity: 1; transform: translateX(0px); }
  100% { opacity: 0; transform: translateX(25%); }
}

@keyframes notyf-fadeoutright { 
  0% { opacity: 1; transform: translateX(0px); }
  100% { opacity: 0; transform: translateX(25%); }
}

@-webkit-keyframes notyf-fadeoutdown { 
  0% { opacity: 1; transform: translateY(0px); }
  100% { opacity: 0; transform: translateY(25%); }
}

@keyframes notyf-fadeoutdown { 
  0% { opacity: 1; transform: translateY(0px); }
  100% { opacity: 0; transform: translateY(25%); }
}

@-webkit-keyframes ripple { 
  0% { transform: scale(0) translateY(-45%) translateX(13%); }
  100% { transform: scale(1) translateY(-45%) translateX(13%); }
}

@keyframes ripple { 
  0% { transform: scale(0) translateY(-45%) translateX(13%); }
  100% { transform: scale(1) translateY(-45%) translateX(13%); }
}

@media only screen and (max-width: 480px) {
  .notyf { padding: 0px; }
  .notyf__ripple { height: 600px; width: 600px; animation-duration: 0.5s; }
  .notyf__toast { max-width: none; border-radius: 0px; box-shadow: rgba(0, 0, 0, 0.13) 0px -2px 7px 0px; width: 100%; }
  .notyf__dismiss { width: 56px; }
}

@-webkit-keyframes bounce { 
  0%, 100% { transform: translateY(-25%); animation-timing-function: cubic-bezier(0.8, 0, 1, 1); }
  50% { transform: none; animation-timing-function: cubic-bezier(0, 0, 0.2, 1); }
}

@keyframes bounce { 
  0%, 100% { transform: translateY(-25%); animation-timing-function: cubic-bezier(0.8, 0, 1, 1); }
  50% { transform: none; animation-timing-function: cubic-bezier(0, 0, 0.2, 1); }
}

.shadow-lg { --tw-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1),
        0 4px 6px -2px rgba(0, 0, 0, 0.05); box-shadow: var(--tw-ring-offset-shadow, 0 0 #0000),
        var(--tw-ring-shadow, 0 0 #0000), var(--tw-shadow); }

.filter { --tw-blur: var(--tw-empty, /*!*/ /*!*/); --tw-brightness: var(--tw-empty, /*!*/ /*!*/); --tw-contrast: var(--tw-empty, /*!*/ /*!*/); --tw-grayscale: var(--tw-empty, /*!*/ /*!*/); --tw-hue-rotate: var(--tw-empty, /*!*/ /*!*/); --tw-invert: var(--tw-empty, /*!*/ /*!*/); --tw-saturate: var(--tw-empty, /*!*/ /*!*/); --tw-sepia: var(--tw-empty, /*!*/ /*!*/); --tw-drop-shadow: var(--tw-empty, /*!*/ /*!*/); filter: var(--tw-blur) var(--tw-brightness) var(--tw-contrast)
        var(--tw-grayscale) var(--tw-hue-rotate) var(--tw-invert)
        var(--tw-saturate) var(--tw-sepia) var(--tw-drop-shadow); }

@keyframes dotty { 
  0% { content: ""; }
  25% { content: "."; }
  50% { content: ".."; }
  75% { content: "..."; }
  100% { content: ""; }
}

@keyframes arrow { 
  0% { opacity: 0; transform: scaleY(0); }
  50% { opacity: 1; transform: scale(1); }
  100% { transform: scale(1); }
}
